import{_ as t,o as a,c as l,ag as o}from"./chunks/framework.DtEl18Xn.js";const s="/getbiji-docs-v3/images/WLB4bWdGUoipNcxjlCBcMaZFn2b.png",p="/getbiji-docs-v3/images/ILAcbcgLKotkc0xofSecBzEQnth.png",e="/getbiji-docs-v3/images/C3EMbvFdeod4UcxyFFFc7B5vned.png",c="/getbiji-docs-v3/images/XJgcbQy2ZohCazxyI06cpc5yn5e.png",n="/getbiji-docs-v3/images/KY2wbf4o5oHpIJxp9KxcGcEInlc.png",r="/getbiji-docs-v3/images/L69PbYPVhodftDxmzbucuppHnHh.png",_="/getbiji-docs-v3/images/QBzsbw4SgotJZQxiHOScuxyZnAg.png",g="/getbiji-docs-v3/images/C7C7bEY4uohmVexL51fcMdQAntY.png",I=JSON.parse('{"title":"声纹识别—让 AI 认识你的声音","description":"","frontmatter":{"title":"声纹识别—让 AI 认识你的声音 ","category":" 如何快速上手记笔记","lastUpdated":"2026-03-14T14:55:13.560Z"},"headers":[],"relativePath":"-如何快速上手记笔记/声纹识别让-ai-认识你的声音-.md","filePath":"-如何快速上手记笔记/声纹识别让-ai-认识你的声音-.md"}'),m={name:"-如何快速上手记笔记/声纹识别让-ai-认识你的声音-.md"};function d(b,i,u,A,h,x){return a(),l("div",null,[...i[0]||(i[0]=[o('<h1 id="声纹识别—让-ai-认识你的声音" tabindex="-1">声纹识别—让 AI 认识你的声音 <a class="header-anchor" href="#声纹识别—让-ai-认识你的声音" aria-label="Permalink to &quot;声纹识别—让 AI 认识你的声音&quot;">​</a></h1><p>录音转写自动标记「你说的话」，多人对话一目了然</p><p>Get笔记全新推出声纹识别功能，录入你的声音后，AI 即可在录音笔记中自动识别并标记你的发言。多人会议、访谈对话，每句话都能对号入座，回顾整理更高效。</p><p><strong>适用场景</strong></p><ul><li>团队会议：多人讨论时自动区分每位发言者，快速定位自己说了什么</li><li>采访访谈：记者与受访者对话清晰分离，整理稿件效率翻倍</li><li>课堂互动：师生问答场景中，轻松区分老师讲解与自己的提问发言</li><li>头脑风暴：多人创意碰撞，自己的观点都被准确归属，不再混淆</li><li>一对一沟通：导师辅导、客户沟通等场景，双方发言一目了然</li></ul><p><strong>核心功能</strong></p><ul><li>声纹录入：录入一段你的声音，AI 即可学习并记住你的声纹特征</li><li>自动标记：录音转写时，AI 自动将你的发言标记为你的名字，其他人显示为「说话人 2」「说话人 3」等</li><li>多人区分：即使多人同时参与对话，也能智能区分不同说话人</li><li>面向区分不同说话人的录音场景，多人会议、课堂录音、手机内录</li><li>无感使用：声纹识别在后台自动运行，录音和转写流程无需任何额外操作</li></ul><p><strong>使用额度</strong></p><ul><li>会员用户：声纹识别为会员专属功能，开通会员后即可自动识别</li><li>免费用户：可免费试用 10 次（即 10 条录音笔记可进行声纹识别）</li></ul><h1 id="app端——使用说明" tabindex="-1">APP端——使用说明 <a class="header-anchor" href="#app端——使用说明" aria-label="Permalink to &quot;APP端——使用说明&quot;">​</a></h1><ol><li>打开 App，首页左上角菜单点头像，进入「我的账号」页面，在常用操作区域点击「声纹识别」</li><li>进入声纹识别设置页，开启「启用声纹标记」开关</li><li>点击「录入我的声音」，根据提示朗读一段文字，完成声纹采集</li><li>设置完成后，正常使用录音功能即可——AI 会在生成录音笔记时自动匹配声纹，将你的发言标记为你自己</li><li>同时，也支持在已有录音笔记中，点「文字记录」tab，点击某个说话人并勾选“同步至我的声纹”，也可以把对应的声音标记为我自己的声音（仅限没有录入我的声音的情况下）</li></ol><p><img src="'+s+'" alt=""></p><p><img src="'+p+'" alt=""></p><p><img src="'+e+'" alt=""></p><p><img src="'+c+'" alt=""></p><p><img src="'+n+'" alt=""></p><p><img src="'+r+'" alt=""></p><p><img src="'+_+'" alt=""></p><p><img src="'+g+'" alt=""></p>',19)])])}const v=t(m,[["render",d]]);export{I as __pageData,v as default};
